{
  "$schema": "https://vega.github.io/schema/vega-lite/v6.json",
  "description": "Histogram of Total Roof Size of Buildings in Chicago (log-scaled)",
  "data": {
    "name": "data"
  },
  "transform": [
    { "filter": "datum.TOTAL_ROOF_SQFT > 0" },
    {
      "calculate": "log(datum.TOTAL_ROOF_SQFT) / log(10)",
      "as": "log_roof_size"
    }
  ],
  "mark": "bar",
  "encoding": {
    "x": {
      "field": "log_roof_size",
      "bin": { "maxbins": 30 },
      "axis": {
        "title": "Total Roof Size (sqft)",
        "values": [3, 4, 5, 6],
        "labelExpr": "'10^' + datum.value"
      }
    },
    "y": {
      "aggregate": "count",
      "type": "quantitative",
      "axis": {
        "title": "Number of Buildings"
      }
    }
  }
}

{
  "$schema": "https://vega.github.io/schema/vega-lite/v6.json",
  "description": "Dot Density Map of Green Roof Locations in Chicago with Zoom & Pan",
  "width": 500,
  "height": 600,
  "title": "Green Roof Locations in Chicago",
  "mark": "circle",
  "encoding": {
    "x": {
      "field": "LONGITUDE",
      "type": "quantitative",
      "scale": {
        "domain": [
          -88.0,
          -87.5
        ]
      },
      "axis": {
        "title": "Longitude"
      }
    },
    "y": {
      "field": "LATITUDE",
      "type": "quantitative",
      "scale": {
        "domain": [
          41.6,
          42.1
        ]
      },
      "axis": {
        "title": "Latitude"
      }
    },
    "size": {
      "field": "VEGETATED_SQFT",
      "type": "quantitative",
      "legend": {
        "title": "Vegetated Sqft"
      }
    },
    "tooltip": [
      {
        "field": "VEGETATED_SQFT",
        "type": "quantitative"
      },
      {
        "field": "TOTAL_ROOF_SQFT",
        "type": "quantitative"
      },
      {
        "field": "zip",
        "type": "nominal"
      }
    ]
  },
  "config": {
    "view": {
      "stroke": "transparent"
    }
  },
  "params": [
    {
      "name": "grid",
      "select": "interval",
      "bind": "scales"
    }
  ]
}

{
  "$schema": "https://vega.github.io/schema/vega-lite/v6.json",
  "description": "Top 10 largest zip codes by green roof area",
  "width": 400,
  "height": 200,
  "mark": {
    "type": "bar",
    "stroke": "black",
    "color": "green"
  },
  "encoding": {
    "x": {
      "field": "VEGETATED_SQFT",
      "type": "quantitative",
      "axis": {
        "title": "Total Vegetated Roof Size (sqft)",
        "values": [
          100000,
          250000,
          500000,
          1000000
        ],
        "format": ",d"
      }
    },
    "y": {
      "field": "zip",
      "type": "nominal",
      "sort": "-x",
      "axis": {
        "title": "Zip Code"
      }
    },
    "color": {
      "field": "zip",
      "type": "nominal",
      "scale": {
        "scheme": "category20"
      }
    },
    "opacity": {
      "condition": {
        "param": "zip_select",
        "value": 1
      },
      "value": 0.3
    },
    "tooltip": [
      {
        "field": "zip",
        "type": "nominal"
      },
      {
        "field": "VEGETATED_SQFT",
        "type": "quantitative"
      }
    ]
  },
  "params": [
    {
      "name": "zip_select",
      "select": {
        "type": "point",
        "fields": [
          "zip"
        ],
        "toggle": "event.shiftKey"
      }
    }
  ]
}
